### Issue description

I make a ShaderMaterial show outline. and IMO, it good, it look like this:

<img width="903" height="399" alt="Image" src="https://github.com/user-attachments/assets/883b5c41-4689-4b89-b881-4704cddf0340" />

now, i want implement this by CompositorEffect.
all code and parameter was same. but it look diff and ugly.

<img width="951" height="377" alt="Image" src="https://github.com/user-attachments/assets/4064f5c3-7ac7-4275-9892-6d3272402c2a" />


shader code:
``` shader
shader_type spatial;
render_mode unshaded, fog_disabled;


uniform sampler2D depth_texture : hint_depth_texture;
uniform sampler2D color_texture : hint_screen_texture;

uniform vec4 outline_color  : source_color = vec4(0,0,0,1);
uniform float outline_width = 1.0;
uniform float m_in  = 0.0;
uniform float m_ax = 1.0;


		vec3 rgb_to_hsv(vec3 color){
	float r = color.r;
	float g = color.g;
	float b = color.b;

	float max_v = max(max(r,g),b);
	float min_v = min(min(r,g),b);

	float h, s, v;
	v = max_v;
	if (max_v == 0.0){
		s = 0.0;
	}else{
		s = 1.0 - min_v / max_v;
	}

	if (max_v == min_v){
		h = 0.0;
	}
	else if (max_v == r && g>=b){
		h = 60.0*((g-b)/(max_v-min_v));
	}
	else if(max_v == r && g<b){
		h = 60.0*((g-b)/(max_v-min_v))+360.0;
	}
	else if (max_v == g){
		h = 60.0*((b-r)/(max_v-min_v))+120.0;
	}
	else if (max_v == b){
		h = 60.0*((r-g)/(max_v-min_v))+240.0;
	}
	h /= 360.0f;

	return vec3(h,s,v);
}


vec3 hsv_to_rgb(vec3 color){
	float h = color.x * 360.0f;
	float s = color.y;
	float v = color.z;

	float r,g,b;

	if (s==0.0){
		r = g = b = v;
	}
	else{
		h = h / 60.0;
		int i = int(h);
		float c = h - float(i);

		float x = v * (1.0-s);
		float y = v * (1.0 - s*c);
		float z = v * (1.0 - s*(1.0-c));
		switch (i){
			case 0:r=v;g=z;b=x;break;
			case 1:r=y;g=v;b=x;break;
			case 2:r=x;g=v;b=z;break;
			case 3:r=x;g=y;b=v;break;
			case 4:r=z;g=x;b=v;break;
			case 5:r=v;g=x;b=y;break;
		}
	}

	return vec3(r,g,b);
}


void vertex() {
	POSITION = vec4(VERTEX.xy, 1.0, 1.0);
}


	float get_depth(vec2 uv, mat4  inv_projection_matrix) {
		float depth = texture(depth_texture,uv).r;
		vec3 ndc = vec3(uv*2.0-1.0,depth);
		vec4 view = inv_projection_matrix * vec4(ndc,1.0);
		view.xyz /= view.w;
		return -view.z;
	}

		float calc_depth(vec2 uv, vec2 offset, float pre_depth,mat4 inv_projection_matrix){
			float d1 = get_depth(uv+offset,inv_projection_matrix);
			float d2 = get_depth(uv-offset,inv_projection_matrix);
			return max(abs(d1-d2),pre_depth);
		}

void fragment() {
		vec2 pix_size = 1.0/VIEWPORT_SIZE*outline_width;
		vec2 uv = UV*vec2(1,-1);
		float depth = 0.0;
		depth = calc_depth(uv, vec2(pix_size.x,0.0),depth,INV_PROJECTION_MATRIX);
		depth = calc_depth(uv, vec2(0.0,pix_size.y),depth,INV_PROJECTION_MATRIX);
		depth = calc_depth(uv, vec2(pix_size.x,pix_size.y),depth,INV_PROJECTION_MATRIX);
		depth = calc_depth(uv, vec2(-pix_size.x,pix_size.y),depth,INV_PROJECTION_MATRIX);

	vec4 color = texture(color_texture,uv);
	vec3 hsv = rgb_to_hsv(color.rgb);
	float steps = 10.0;
	hsv.g = floor(hsv.g * steps) / steps;
	color.rgb = hsv_to_rgb(hsv);
	color = mix(color, outline_color, smoothstep(m_in,m_ax,depth));
	ALBEDO.rgb = color.rgb;
}


