XCompositorEffectBase.gd
``` gdscript
@tool
extends CompositorEffect
class_name XCompositorEffectBase

const template_shader := "
#version 450

layout(local_size_x = 8, local_size_y = 8, local_size_z = 1) in;
layout(rgba16f, set = 0, binding = 0) uniform image2D color_image;
layout(set = 1, binding = 0) uniform sampler2D depth_texture;
layout(set = 2, binding = 0, std430) restrict buffer Params {
	vec2 resolution;
	mat4 inv_view_matrix;
	mat4 projection_matrix;
	mat4 inv_projection_matrix;
	#OTHER_PARAMS
} params;

#FUNCS_CODE

void main() {
	ivec2 coords = ivec2(gl_GlobalInvocationID.xy);
	vec2 pix_size = vec2(1.0)/params.resolution;
	vec2 uv = vec2(coords)*pix_size;

	vec4 color = imageLoad(color_image, coords);

	#COMPUTE_CODE

	imageStore(color_image, coords, color);
}"


var rd: RenderingDevice
var nearest_sampler: RID
var shader: RID
var pipeline: RID
var params_buffer: RID
var other_params_name := PackedStringArray()

func _get_compute_code()->String:
	return ""


func _get_funcs_code()->String:
	return ""


func add_param(param_name:String):
	other_params_name.append(param_name)


func gen_other_params_code()->String:
	var type_dic = {
		TYPE_FLOAT: "float",
		TYPE_COLOR: "vec4",
	}
	var ss = PackedStringArray()
	for i in other_params_name:
		var p = get(i)
		var type = typeof(p)
		if type_dic.has(type):
			ss.append("%s %s;"%[type_dic[type], i])
		else:
			assert(false, "Unsupport type.")
	return "\n".join(ss)


func _init():
	effect_callback_type = CompositorEffect.EFFECT_CALLBACK_TYPE_POST_TRANSPARENT
	RenderingServer.call_on_render_thread(_initialize_compute)


func _notification(what):
	if what == NOTIFICATION_PREDELETE:
		if shader.is_valid():
			rd.free_rid(shader)
		if params_buffer.is_valid():
			rd.free_rid(params_buffer)


func _initialize_compute():
	rd = RenderingServer.get_rendering_device()
	if not rd:
		return

	var sampler_state: RDSamplerState = RDSamplerState.new()
	sampler_state.min_filter = RenderingDevice.SAMPLER_FILTER_NEAREST
	sampler_state.mag_filter = RenderingDevice.SAMPLER_FILTER_NEAREST
	nearest_sampler = rd.sampler_create(sampler_state)

	var full_shader_code = template_shader
	full_shader_code = full_shader_code.replace("#OTHER_PARAMS", gen_other_params_code())
	full_shader_code = full_shader_code.replace("#FUNCS_CODE", _get_funcs_code())
	full_shader_code = full_shader_code.replace("#COMPUTE_CODE", _get_compute_code())

	var shader_source := RDShaderSource.new()
	shader_source.language = RenderingDevice.SHADER_LANGUAGE_GLSL
	shader_source.source_compute = full_shader_code
	var shader_spirv: RDShaderSPIRV = rd.shader_compile_spirv_from_source(shader_source)
	if shader_spirv.compile_error_compute != "":
		push_error(shader_spirv.compile_error_compute)
		push_error("\nshader_code:\n",full_shader_code)
		return

	shader = rd.shader_create_from_spirv(shader_spirv)
	pipeline = rd.compute_pipeline_create(shader)


func _render_callback(effect_callback_type, render_data):
	if not rd:
		return
	if effect_callback_type != CompositorEffect.EFFECT_CALLBACK_TYPE_POST_TRANSPARENT:
		return

	var render_scene_buffers: RenderSceneBuffersRD = render_data.get_render_scene_buffers()
	var render_scene_data : RenderSceneDataRD = render_data.get_render_scene_data()

	if not render_scene_buffers or not render_scene_data:
		return

	var size = render_scene_buffers.get_internal_size()
	if size.x == 0 and size.y == 0:
		return
	var x_groups = (size.x - 1) / 8 + 1
	var y_groups = (size.y - 1) / 8 + 1

	# Loop through views just in case we're doing stereo rendering. No extra cost if this is mono.
	var view_count = render_scene_buffers.get_view_count()
	for view in range(view_count):
		var color_image = render_scene_buffers.get_color_layer(view)
		var depth_image = render_scene_buffers.get_depth_layer(view)

		var inv_view_matrix: Transform3D = render_scene_data.get_cam_transform()
		var projection_matrix: Projection = render_scene_data.get_view_projection(view)

		var uniform: RDUniform = RDUniform.new()
		uniform.uniform_type = RenderingDevice.UNIFORM_TYPE_IMAGE
		uniform.binding = 0
		uniform.add_id(color_image)
		var color_set = UniformSetCacheRD.get_cache(shader, 0, [ uniform ])

		uniform = RDUniform.new()
		uniform.uniform_type = RenderingDevice.UNIFORM_TYPE_SAMPLER_WITH_TEXTURE
		uniform.binding = 0
		uniform.add_id(nearest_sampler)
		uniform.add_id(depth_image)
		var depth_set = UniformSetCacheRD.get_cache(shader, 1, [ uniform ])

		var params: PackedFloat32Array = PackedFloat32Array()
		push_vec2_to_arr(params,size)
		push_transform3d_to_arr(params,inv_view_matrix)
		push_projection_to_arr(params,projection_matrix)
		push_projection_to_arr(params,projection_matrix.inverse())
		for i in other_params_name:
			push_var_to_arr(params, get(i))
		#for i in 2:
			#params.push_back(10.0);
		if params_buffer.is_valid():
			rd.buffer_update(params_buffer, 0, params.size() * 4, params.to_byte_array())
		else:
			params_buffer = rd.storage_buffer_create(params.size() * 4, params.to_byte_array())
		uniform = RDUniform.new()
		uniform.uniform_type = RenderingDevice.UNIFORM_TYPE_STORAGE_BUFFER
		uniform.binding = 0
		uniform.add_id(params_buffer)
		var params_set := UniformSetCacheRD.get_cache(shader, 2, [uniform])

		var compute_list := rd.compute_list_begin()
		rd.compute_list_bind_compute_pipeline(compute_list, pipeline)
		rd.compute_list_bind_uniform_set(compute_list, color_set, 0)
		rd.compute_list_bind_uniform_set(compute_list, depth_set, 1)
		rd.compute_list_bind_uniform_set(compute_list, params_set, 2)
		rd.compute_list_dispatch(compute_list, x_groups, y_groups, 1)
		rd.compute_list_end()


func push_float_to_arr(arr:PackedFloat32Array, v:float):
	arr.push_back(v)
	arr.append_array([0.0,0.0,0.0])


func push_vec2_to_arr(arr:PackedFloat32Array, vec2:Vector2):
	arr.push_back(vec2.x)
	arr.push_back(vec2.y)
	arr.append_array([0.0,0.0])


func push_vec3_to_arr(arr:PackedFloat32Array, vec3:Vector3):
	arr.push_back(vec3.x)
	arr.push_back(vec3.y)
	arr.push_back(vec3.z)
	arr.append_array([0.0])


func push_vec4_to_arr(arr:PackedFloat32Array, vec4:Vector4):
	arr.push_back(vec4.x)
	arr.push_back(vec4.y)
	arr.push_back(vec4.z)
	arr.push_back(vec4.w)


func push_color_to_arr(arr:PackedFloat32Array, v:Color):
	arr.push_back(v.r)
	arr.push_back(v.g)
	arr.push_back(v.b)
	arr.push_back(v.a)

func push_transform3d_to_arr(arr:PackedFloat32Array, transform:Transform3D):
	push_vec3_to_arr(arr,transform.basis.x)
	push_vec3_to_arr(arr,transform.basis.y)
	push_vec3_to_arr(arr,transform.basis.z)
	push_vec3_to_arr(arr,transform.origin)


func push_projection_to_arr(arr:PackedFloat32Array, proj:Projection):
	push_vec4_to_arr(arr,proj.x)
	push_vec4_to_arr(arr,proj.y)
	push_vec4_to_arr(arr,proj.z)
	push_vec4_to_arr(arr,proj.w)


func push_var_to_arr(arr:PackedFloat32Array, n :Variant):
	var type = typeof(n)
	match type:
		TYPE_FLOAT:
			push_float_to_arr(arr,n)
		TYPE_COLOR:
			push_color_to_arr(arr,n)
		_:
			assert(false,"Unspport type")

