@tool
extends XCompositorEffectBase
class_name XCompositorEffectCartoon

@export_range(0.0,10.0,0.1) var outline_width := 1.0
@export var outline_color := Color.BLACK

@export_range(0.0,1.0,0.001) var m_in := 0.05
@export_range(0.0,1.0,0.01) var m_ax := 1.0

func _init() -> void:
	add_param("outline_width")
	add_param("outline_color")
	add_param("m_in")
	add_param("m_ax")
	super()


func _get_compute_code()->String:
	return "
		float depth = 0.0;
		depth = calc_depth(uv, vec2(pix_size.x,0.0),depth);
		depth = calc_depth(uv, vec2(0.0,pix_size.y),depth);
		depth = calc_depth(uv, vec2(pix_size.x,pix_size.y),depth);
		depth = calc_depth(uv, vec2(-pix_size.x,pix_size.y),depth);

		vec3 hsv = rgb_to_hsv(color.rgb);
		float steps = 10.0;
		hsv.g = floor(hsv.g * steps) / steps;
		color.rgb = hsv_to_rgb(hsv);
		color = mix(color, params.outline_color, smoothstep(params.m_in,params.m_ax,depth));
	"


func _get_funcs_code()->String:
	return "
	float get_depth(vec2 uv) {
		float depth = texture(depth_texture,uv).r;
		vec3 ndc = vec3(uv*2.0-1.0,depth);
		vec4 view =  params.inv_projection_matrix * vec4(ndc,1.0);
		view.xyz /= view.w;
		return -view.z;
	}

		float calc_depth(vec2 uv, vec2 offset, float pre_depth){
			float d1 = get_depth(uv+offset);
			float d2 = get_depth(uv-offset);
			return max(abs(d1-d2),pre_depth);
		}

		vec3 rgb_to_hsv(vec3 color){
	float r = color.r;
	float g = color.g;
	float b = color.b;

	float max_v = max(max(r,g),b);
	float min_v = min(min(r,g),b);

	float h, s, v;
	v = max_v;
	if (max_v == 0.0){
		s = 0.0;
	}else{
		s = 1.0 - min_v / max_v;
	}

	if (max_v == min_v){
		h = 0.0;
	}
	else if (max_v == r && g>=b){
		h = 60.0*((g-b)/(max_v-min_v));
	}
	else if(max_v == r && g<b){
		h = 60.0*((g-b)/(max_v-min_v))+360.0;
	}
	else if (max_v == g){
		h = 60.0*((b-r)/(max_v-min_v))+120.0;
	}
	else if (max_v == b){
		h = 60.0*((r-g)/(max_v-min_v))+240.0;
	}
	h /= 360.0f;

	return vec3(h,s,v);
}


vec3 hsv_to_rgb(vec3 color){
	float h = color.x * 360.0f;
	float s = color.y;
	float v = color.z;

	float r,g,b;

	if (s==0.0){
		r = g = b = v;
	}
	else{
		h = h / 60.0;
		int i = int(h);
		float c = h - float(i);

		float x = v * (1.0-s);
		float y = v * (1.0 - s*c);
		float z = v * (1.0 - s*(1.0-c));
		switch (i){
			case 0:r=v;g=z;b=x;break;
			case 1:r=y;g=v;b=x;break;
			case 2:r=x;g=v;b=z;break;
			case 3:r=x;g=y;b=v;break;
			case 4:r=z;g=x;b=v;break;
			case 5:r=v;g=x;b=y;break;
		}
	}

	return vec3(r,g,b);
}
